public class CircularQueue {

    private int[] data;
    private int head, tail, size, capacity;

    public CircularQueue(int capacity) {
        this.capacity = capacity;
        data = new int[capacity];
        head = tail = size = 0;
    }

    public void enqueue(int val) {
        if (isFull()) throw new RuntimeException("Queue full");
        // TODO: store val at tail, advance tail circularly, increment size
    }

    public int dequeue() {
        if (isEmpty()) throw new RuntimeException("Queue empty");
        int val = data[head];
        // TODO: advance head circularly, decrement size
        return val;
    }

    public int peek() {
        if (isEmpty()) throw new RuntimeException("Queue empty");
        return data[head];
    }

    public boolean isEmpty() { return size == 0; }
    public boolean isFull() { return size == capacity; }

    public void printState() {
        System.out.print("Queue: ");
        int idx = head;
        for (int i = 0; i < size; i++) {
            System.out.print(data[idx]);
            if (i < size - 1) System.out.print(", ");
            idx = (idx + 1) % capacity;
        }
        System.out.println(" [size=" + size + "]");
    }

    public static void main(String[] args) {
        CircularQueue cq = new CircularQueue(4);
        cq.enqueue(1); cq.enqueue(2); cq.enqueue(3);
        cq.printState();
        System.out.println("Dequeue: " + cq.dequeue());
        cq.enqueue(4); cq.enqueue(5);
        cq.printState();
        System.out.println("Full: " + cq.isFull());
    }
}

public class MaxPriorityQueue {

    private int[] heap;
    private int size;

    public MaxPriorityQueue(int capacity) {
        heap = new int[capacity + 1]; // 1-indexed
        size = 0;
    }

    private void swap(int i, int j) {
        int tmp = heap[i]; heap[i] = heap[j]; heap[j] = tmp;
    }

    public void insert(int val) {
        heap[++size] = val;
        // TODO: swim up: while size > 1 and heap[k] > heap[k/2], swap k with k/2
        int k = size;
        while (k > 1 && heap[k] > heap[k / 2]) {
            swap(k, k / 2);
            k = k / 2;
        }
    }

    public int extractMax() {
        int max = heap[1];
        swap(1, size--);
        // TODO: sink down from position 1
        //   while 2*k <= size: find larger child j; if heap[k]>=heap[j] break; swap k,j; k=j
        return max;
    }

    public int peek() { return heap[1]; }
    public int size() { return size; }

    public static void main(String[] args) {
        MaxPriorityQueue pq = new MaxPriorityQueue(10);
        pq.insert(3); pq.insert(1); pq.insert(4); pq.insert(1); pq.insert(5);
        System.out.println("Max: " + pq.peek());
        System.out.println(pq.extractMax());
        System.out.println(pq.extractMax());
        System.out.println(pq.extractMax());
    }
}

public class Deque {

    private static class Node {
        int val; Node prev, next;
        Node(int v) { val = v; }
    }

    private Node head, tail;
    private int size;

    public void addFirst(int val) {
        Node n = new Node(val);
        if (head == null) { head = tail = n; }
        else { n.next = head; head.prev = n; head = n; }
        size++;
    }

    public void addLast(int val) {
        // TODO: add to tail end
    }

    public int removeFirst() {
        if (head == null) throw new RuntimeException("Empty");
        int v = head.val;
        if (head == tail) { head = tail = null; }
        else { head = head.next; head.prev = null; }
        size--;
        return v;
    }

    public int removeLast() {
        // TODO: remove from tail end
        return -1;
    }

    public int peekFirst() { return head != null ? head.val : -1; }
    public int peekLast() { return tail != null ? tail.val : -1; }
    public int size() { return size; }

    public static void main(String[] args) {
        Deque dq = new Deque();
        dq.addLast(1); dq.addLast(2); dq.addLast(3);
        System.out.println("As queue (FIFO):");
        System.out.println(dq.removeFirst() + ", " + dq.removeFirst() + ", " + dq.removeFirst());
        dq.addFirst(3); dq.addFirst(2); dq.addFirst(1);
        System.out.println("As stack (LIFO):");
        System.out.println(dq.removeFirst() + ", " + dq.removeFirst() + ", " + dq.removeFirst());
    }
}
